{"code": "import json
import re

# Load the full books data
with open('var_functions.query_db:62', 'r') as f:
    books_data = json.load(f)

print('Loaded', len(books_data), 'books')

# Function to extract publication year
def extract_year(details):
    if not details:
        return None

    # Try multiple patterns
    patterns = [
        r'(?:January|February|March|April|May|June|July|August|September|October|November|December)[^\d]*(\d{4})',
        r'published[^\d]*(\d{4})',
        r'released[^\d]*(\d{4})',
        r'\b(19\d{2}|20[0-2]\d)\b'
    ]

    for pattern in patterns:
        match = re.search(pattern, details, re.IGNORECASE)
        if match:
            year = int(match.group(1))
            if 1900 <= year <= 2023:
                return year
    return None

# Extract years
book_years = {}
for book in books_data:
    year = extract_year(book['details'])
    if year:
        book_years[book['book_id']] = year

print('Successfully extracted years for', len(book_years), 'books')
print('Sample mappings:', list(book_years.items())[:10])

print('__RESULT__:')
print(json.dumps({
    'books_processed': len(book_years),
    'sample': list(book_years.items())[:10]
}))"}

